import React, { useEffect } from "react";
import AOS from "aos";
import "aos/dist/aos.css";
import "./HomePage.css";

export default function HomePage() {
  useEffect(() => {
    AOS.init({
      duration: 600, // Faster animation
      once: true,
      offset: 120,
    });
  }, []);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  return (
    <div className="homepage">
      {/* Hero Section */}
      <section className="hero-section">
        <h1 data-aos="fade-up">Welcome to CampusConnect</h1>
        <p data-aos="fade-up" data-aos-delay="100">
          Your one-stop platform for all college needs.
        </p>
        <a href="#services" data-aos="zoom-in" data-aos-delay="200">
          <button className="get-started-btn">Get Started</button>
        </a>
      </section>

      {/* Services Section */}
      <section id="services" className="section" data-aos="fade-up">
        <h2>Our Services</h2>
        <div className="card-container">
          <div className="card" data-aos="zoom-in" data-aos-delay="100">Notices</div>
          <div className="card" data-aos="zoom-in" data-aos-delay="200">Internships</div>
          <div className="card" data-aos="zoom-in" data-aos-delay="300">Placements</div>
        </div>
      </section>

      {/* Features Section */}
      <section className="section" id="features" data-aos="fade-up">
        <h2>Features</h2>
        <ul>
          <li data-aos="fade-right">Real-time updates</li>
          <li data-aos="fade-right" data-aos-delay="100">Role-based access</li>
          <li data-aos="fade-right" data-aos-delay="200">Responsive Design</li>
        </ul>
      </section>

      {/* Testimonials Section */}
      <section className="section" id="testimonials" data-aos="fade-up">
        <h2>Testimonials</h2>
        <p data-aos="fade-in">"CampusConnect made my college life 10x easier!" – A Student</p>
      </section>

      {/* Contact Section */}
      <section className="section" id="contact" data-aos="fade-up">
        <h2>Contact Us</h2>
        <p>Email: support@campusconnect.com</p>
      </section>

      {/* Scroll to top */}
      <button className="scroll-top" onClick={scrollToTop}>↑</button>
    </div>
  );
}
